# Tool definition and runtime for function calling
from typing import Any, Callable
import json

# === Step 1: Define tool as JSON schema ===
TOOLS = [
    {
        "name": "search_web",
        "description": "Search the web for a query. Returns top 5 results with titles and URLs.",
        "parameters": {
            "type": "object",
            "properties": {
                "query": {"type": "string", "description": "Search query string"},
                "num_results": {"type": "integer", "default": 5},
            },
            "required": ["query"]
        }
    },
    {
        "name": "calculator",
        "description": "Evaluate a mathematical expression. Returns numeric result.",
        "parameters": {
            "type": "object",
            "properties": {
                "expression": {"type": "string", "description": "Math expression (e.g., '3 * 4 + 2')"},
            },
            "required": ["expression"]
        }
    },
]

# === Step 2: Tool dispatch registry ===
class ToolRuntime:
    def __init__(self):
        self.registry: dict[str, Callable] = {}

    def register(self, name: str, fn: Callable):
        self.registry[name] = fn

    def dispatch(self, tool_name: str, args: dict) -> str:
        if tool_name not in self.registry:
            return f"Error: tool '{tool_name}' not found"
        try:
            result = self.registry[tool_name](**args)
            return json.dumps(result)
        except Exception as e:
            return f"Error executing {tool_name}: {e}"

# === Step 3: Agent loop with tool calling ===
def agent_with_tools(llm, prompt: str, runtime: ToolRuntime, max_turns: int = 10):
    messages = [{"role": "system", "content": "You have access to tools. Call them when needed."},
                {"role": "user", "content": prompt}]

    for turn in range(max_turns):
        response = llm.chat(messages, tools=TOOLS)

        if response.finish_reason == "stop":
            return response.content  # Final answer

        elif response.finish_reason == "tool_calls":
            for tc in response.tool_calls:
                result = runtime.dispatch(tc.name, json.loads(tc.args))
                messages.append({"role": "tool", "name": tc.name, "content": result})

    raise TimeoutError(f"Agent did not finish in {max_turns} turns")

# ponytail: parallel calls when tools are independent — reduces wall-clock
# latency from sum(t_exec) to max(t_exec) at the same token cost.

# Multi-agent system with router + specialist workers
from typing import Optional
from dataclasses import dataclass, field

@dataclass
class AgentMessage:
    sender: str
    recipient: str  # "all" for broadcast
    content: str
    round: int = 0

class MessageBus:
    def __init__(self):
        self.messages: list[AgentMessage] = []

    def post(self, msg: AgentMessage):
        self.messages.append(msg)

    def read_for(self, agent: str, since_round: int = 0) -> list[AgentMessage]:
        return [m for m in self.messages
                if (m.recipient in ("all", agent)) and m.round >= since_round]

class Agent:
    def __init__(self, name: str, llm, system_prompt: str):
        self.name = name
        self.llm = llm
        self.system_prompt = system_prompt

    def act(self, task: str, bus: MessageBus, round_num: int) -> AgentMessage:
        context = "\n".join(f"{m.sender}: {m.content}" for m in bus.read_for(self.name))
        prompt = f"{self.system_prompt}\nTask: {task}\nMessages: {context}\nYour response:"
        response = self.llm.generate(prompt)
        return AgentMessage(sender=self.name, recipient="all",
                           content=response, round=round_num)


class Coordinator:
    def __init__(self, agents: list[Agent], llm):
        self.agents = agents
        self.llm = llm

    def run(self, task: str, max_rounds: int = 5) -> str:
        bus = MessageBus()
        bus.post(AgentMessage("system", "all", f"Task: {task}", round=0))

        for round_num in range(1, max_rounds + 1):
            for agent in self.agents:
                msg = agent.act(task, bus, round_num)
                bus.post(msg)

            # Coordinator checks for consensus or deadlock
            recent = bus.read_for("coordinator", since_round=round_num - 1)
            consensus = self.llm.generate(
                f"Do these agents agree?\n{recent}\n"
                f"If yes, produce final answer. If no, say 'no' and why."
            )
            if not consensus.startswith("no"):
                return consensus

        return f"No consensus after {max_rounds} rounds. Best answer: {bus.messages[-1].content}"

# ponytail: 3-agent panel (coder, reviewer, tester) is sweet spot.
# More than 5 agents → coordination cost > accuracy benefit.
# Debates >5 rounds → diminishing returns.
